const PRICE = {
  input:       1.1   / 1_000_000,
  inputCached: 0.275 / 1_000_000,
  output:      4.4   / 1_000_000,
};

function pickUsage(obj = {}) {
  const v1 = obj.kwargs?.response_metadata?.usage;
  if (v1) {
    return {
      prompt:       v1.prompt_tokens       ?? v1.input_tokens       ?? 0,
      completion:   v1.completion_tokens   ?? v1.output_tokens      ?? 0,
      cached:       v1.prompt_tokens_details?.cached_tokens ?? 0,
    };
  }
  const v2 = obj.usage_metadata;
  if (v2) {
    return {
      prompt:       v2.input_tokens  ?? 0,
      completion:   v2.output_tokens ?? 0,
      cached:       v2.input_token_details?.cache_read ?? 0,
    };
  }
  const v3 = obj.usage;
  if (v3) {
    return {
      prompt:       v3.prompt_tokens ?? v3.input_tokens ?? 0,
      completion:   v3.completion_tokens ?? v3.output_tokens ?? 0,
      cached:       v3.cached_tokens ?? 0,
    };
  }
  return { prompt: 0, completion: 0, cached: 0 };
}

let promptT = 0, completionT = 0, cachedT = 0;
const steps = [];
let summary = '';

for (const item of $input.all()) {
  const conversations = Array.isArray(item.json) ? item.json : [item.json];

  for (const convo of conversations) {
    summary = convo.output ?? summary;

    if (Array.isArray(convo.intermediateSteps)) {
      for (const step of convo.intermediateSteps) {
        if (!step.action) continue;

        const msg = step.action.messageLog?.[0] ?? step.action;
        const u = pickUsage(msg);
        promptT     += u.prompt;
        completionT += u.completion;
        cachedT     += u.cached;

        steps.push({
          tool:        step.action.tool,
          toolInput:   step.action.toolInput,
          observation: step.observation,
        });
      }
    }
  }
}

const nonCached = promptT - cachedT;
const cost = (nonCached * PRICE.input) +
             (cachedT   * PRICE.inputCached) +
             (completionT * PRICE.output);

const result = {
  summary,
  promptTokens:     promptT,
  completionTokens: completionT,
  cachedTokens:     cachedT,
  costUSD:          +cost.toFixed(6),
  totalCostUSD:     +cost.toFixed(6), // opcional: pode remover se quiser evitar repetiГ§ГЈo
  steps
};

// --- NormalizaГ§ГЈo pro Supabase (opcional se jГЎ tiver campos fixos na tabela) ---
const allKeys = [...new Set(Object.keys(result))];
const norm = {};
for (const key of allKeys) {
  norm[key] = result[key] ?? null;
}

return [{ json: norm }];

// 1. Ordena as mensagens pela data (da mais antiga para a mais recente)
items.sort((a, b) => new Date(a.json.created_at) - new Date(b.json.created_at));

// 2. Pega apenas as Гәltimas 50 mensagens caso o histГіrico seja muito longo
const itensRecentes = items.slice(-50);

function formatarData(isoDate) {
  const d = new Date(isoDate);
  const dia = String(d.getDate()).padStart(2, '0');
  const mes = String(d.getMonth() + 1).padStart(2, '0');
  const ano = d.getFullYear();
  return `${dia}/${mes}/${ano}`;
}

const historico = [];

for (const item of itensRecentes) {
  const row = item.json;
  const dataFormatada = formatarData(row.created_at);

  // Processa mensagem do UsuГЎrio
  if (row.mensagem_usuario && row.mensagem_usuario.toString().trim() !== "") {
    historico.push(`${dataFormatada} - UsuГЎrio: ${row.mensagem_usuario.toString().trim()}`);
  }

  // Processa mensagem do Agente
  if (row.mensagem_agente && row.mensagem_agente.toString().trim() !== "") {
    // Caso a mensagem do agente venha como array/objeto de outro fluxo, converte para string
    const msgAgente = typeof row.mensagem_agente === 'string' 
      ? row.mensagem_agente 
      : JSON.stringify(row.mensagem_agente);

    historico.push(`${dataFormatada} - Agente: ${msgAgente.trim()}`);
  }
}

return [
  {
    json: {
      historico_conversa: historico.join("\n\n")
    }
  }
];

